pseudocodeExamples.javaCode:
import stanford.karel.*;
public class FillRowKarel extends Karel {
    public void run() {
        putBeeper();
        while (frontIsClear()) {
            move();
            putBeeper();
        }
    }
}

import stanford.karel.*;
public class HurdleKarel extends SuperKarel {
    public void run() {
        if (frontIsBlocked()) {
            climbHurdle();
        } else {
            move();
        }
    }
    private void climbHurdle() {
        turnLeft();
        move();
        turnRight();
        move();
        turnRight();
        move();
        turnLeft();
    }
}

import stanford.karel.*;
public class SweepRowKarel extends Karel {
    public void run() {
        pickIfPresent();
        while (frontIsClear()) {
            move();
            pickIfPresent();
        }
    }
    private void pickIfPresent() {
        if (beepersPresent()) {
            pickBeeper();
        }
    }
}

